import { Component, OnInit } from "@angular/core";
import { AlertService } from "src/app/core/services/alert.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { User } from "src/app/views/Models/Permissions/User";
import { Funders } from "src/app/views/Models/References/Funders";
import { pagingService } from "src/app/core/services/paging.service";

interface UserSearchInterface {
  visible: boolean;
  selectedUser: User;
}
interface SelectedUserInterface {
  funderCodeThatHasPermissionOnIt: Funders[];
}

@Component({
  selector: "app-add-funder-code-for-user",
  templateUrl: "./add-funder-code-for-user.page.html",
  styleUrls: ["./add-funder-code-for-user.page.scss"],
})
export class AddFunderCodeForUserPage implements OnInit {
  constructor(
    private alertService: AlertService,
    private referencesService: ReferencesService,
    public pagingService: pagingService
  ) {}

  //#region Variables
  showLoader: boolean = false;
  userSearch: UserSearchInterface;
  pagingObject: { page: number };
  allFunderCodesInSystem: Funders[];
  selectedUser: SelectedUserInterface;
  //#endregion

  async ngOnInit() {
    this.showLoader = true;
    this.initializeState();
    this.allFunderCodesInSystem = await this.referencesService
      .getAllFunderCodeInSystem()
      .toPromise();

    this.showLoader = false;
  }

  async initializeState() {
    this.userSearch = {
      visible: true,
      selectedUser: null,
    };
    this.pagingObject = {
      page: 1, // the page we are viewing
    };
    this.selectedUser = { funderCodeThatHasPermissionOnIt: [] };
    this.allFunderCodesInSystem = await this.referencesService
      .getAllFunderCodeInSystem()
      .toPromise();
  }

  async userSelected($event: User) {
    try {
      this.showLoader = true;
      this.userSearch.selectedUser = $event;
      this.selectedUser.funderCodeThatHasPermissionOnIt =
        await this.referencesService
          .getAllFunderCodeForSpecificUser(
            this.userSearch.selectedUser.user_name
          )
          .toPromise();

      this.userSearch.visible = false;
    } catch (error) {
      console.error(error);
      this.alertService.showAlertError(
        error?.message || "حدث خطا في البيانات",
        false
      );
    } finally {
      this.showLoader = false;
    }
  }
  backButton() {
    if (!this.userSearch.visible) {
      this.initializeState();
    }
  }
  changePaginationPage = async (newPage: number): Promise<void> => {
    this.pagingObject.page = newPage;
    try {
      this.showLoader = true;
      this.allFunderCodesInSystem = await this.referencesService
        .getAllFunderCodeInSystem()
        .toPromise();
    } catch (error) {
      console.log("error", error);
      this.alertService.showAlertError(
        error?.message || "حدث خطا في البيانات",
        false
      );
    } finally {
      this.showLoader = false;
    }
  };

  async removeAllPermissionsFromUserBtn() {
    try {
      this.showLoader = true;
      var alertText = "إلغاء";
      if (
        !(await this.alertService.SaveAlert(
          `هل تريد ${alertText} جميع الصلاحيات؟`
        ))
      ) {
        this.showLoader = false;
        return;
      }
      await this.referencesService
        .manageUserAllFunderCodePermission(
          this.userSearch.selectedUser.user_name,
          1
        )
        .toPromise();
      this.selectedUser.funderCodeThatHasPermissionOnIt =
        await this.referencesService
          .getAllFunderCodeForSpecificUser(
            this.userSearch.selectedUser.user_name
          )
          .toPromise();
    } catch (error) {
      console.error(error);
      this.alertService.showAlertError(error?.message || "حدث خطا", false);
    } finally {
      this.showLoader = false;
    }
  }
  async giveAllPermissionsToUserBtn() {
    try {
      this.showLoader = true;
      var alertText = "منح";
      if (
        !(await this.alertService.SaveAlert(
          `هل تريد ${alertText} جميع الصلاحيات؟`
        ))
      ) {
        this.showLoader = false;
        return;
      }
      await this.referencesService
        .manageUserAllFunderCodePermission(
          this.userSearch.selectedUser.user_name,
          2
        )
        .toPromise();
      this.selectedUser.funderCodeThatHasPermissionOnIt =
        await this.referencesService
          .getAllFunderCodeForSpecificUser(
            this.userSearch.selectedUser.user_name
          )
          .toPromise();
    } catch (error) {
      console.error(error);
      this.alertService.showAlertError(error?.message || "حدث خطا", false);
    } finally {
      this.showLoader = false;
    }
  }
  checkIfClientHasPermissionOnSpecificFunderCode = (
    funderCode: string
  ): boolean => {
    return this.selectedUser.funderCodeThatHasPermissionOnIt.some(
      (funder) => funder.funder_code === funderCode
    );
  };
  async removePermissionOnSpecificFunderCode(funderCode: string) {
    try {
      this.showLoader = true;
      await this.referencesService
        .manageUserFunderCodePermission(
          this.userSearch.selectedUser.user_name,
          Number(funderCode),
          1
        )
        .toPromise();
      const funderIndex =
        this.selectedUser.funderCodeThatHasPermissionOnIt.findIndex(
          (funder) => funder.funder_code === funderCode
        );
      this.selectedUser.funderCodeThatHasPermissionOnIt.splice(funderIndex, 1);
    } catch (error) {
      this.alertService.showAlertError(error.message, false);
    } finally {
      this.showLoader = false;
    }
  }
  async addPermissionOnSpecificFunderCode(funderCode: string) {
    try {
      this.showLoader = true;
      await this.referencesService
        .manageUserFunderCodePermission(
          this.userSearch.selectedUser.user_name,
          Number(funderCode),
          2
        )
        .toPromise();
      this.selectedUser.funderCodeThatHasPermissionOnIt.push(
        this.getFunderCodeInformation(funderCode)
      );
    } catch (error) {
      this.alertService.showAlertError(error.message, false);
    } finally {
      this.showLoader = false;
    }
  }
  getFunderCodeInformation = (funderCode: string): Funders => {
    const funderCodeInfo = this.allFunderCodesInSystem.find(
      (funder) => funder.funder_code === funderCode
    );
    return funderCodeInfo;
  };
  toggleEnableAllOrDisableAllBtn(): {
    disableRemoveAllFunderPermissionBtn: boolean;
    disableAddAllFunderPermissionBtn: boolean;
  } {
    return {
      disableAddAllFunderPermissionBtn:
        this.selectedUser.funderCodeThatHasPermissionOnIt.length ===
        this.allFunderCodesInSystem.length,
      disableRemoveAllFunderPermissionBtn:
        this.selectedUser.funderCodeThatHasPermissionOnIt.length === 0,
    };
  }
}
